// Normalizar respuesta de MyMiniFactory al formato RenderHub
const response = $input.first().json;
const items = response.items || response.objects || [];
const query = $('Trigger Sub-Workflow').first().json.query || '';

const normalized = items.map(item => {
  // Extraer thumbnail de images array
  const thumb = item.images?.[0]?.thumbnail?.url ||
                item.images?.[0]?.url ||
                item.main_image?.thumbnail?.url || '';

  // Extraer URL de descarga de files array (buscar STL)
  const stlFile = (item.files || []).find(f =>
    (f.filename || '').toLowerCase().includes('.stl')
  );
  const downloadUrl = stlFile?.download_url || item.object_url || null;

  return {
    platform: 'MyMiniFactory',
    id: String(item.id),
    name: item.name || '',
    description: (item.description || '').replace(/<[^>]*>/g, '').slice(0, 300),
    thumbnail_url: thumb,
    page_url: item.url || `https://www.myminifactory.com/object/${item.id}`,
    download_url: downloadUrl,
    stl_direct: !!stlFile,
    creator: item.designer?.username || '',
    likes: item.likes_count || 0,
    downloads: item.download_count || 0,
    tags: (item.tags || []).map(t => t.name || t).slice(0, 8)
  };
});

return {
  platform: 'MyMiniFactory',
  query,
  count: normalized.length,
  results: normalized
};

